    xAxis.ActualRangeChanged += xAxis_ActualRangeChanged;

    private void xAxis_ActualRangeChanged(object sender, Syncfusion.Maui.Charts.ActualRangeChangedEventArgs e)
    {
        e.VisibleMinimum = 2;
        e.VisibleMaximum = 5;
        e.ActualMinimum = 0;
        e.ActualMaximum = 8;
    } 

