       ThermalExpansion.Add(new Model() { Name="Thuilium",Value=8.45,High=7.1 });
       ThermalExpansion.Add(new Model() { Name="Steel",Value=9.7,High=8.6});
       ThermalExpansion.Add(new Model() { Name="Tin",Value=14.6,High=10.8 });
