member.remarks:

To customize connector lines, create an instance of the  class, and set it to the ConnectorLineSettings property of the CircularDataLabelSettings.
             # [Xaml](#tab/tabid-1)

                <chart:SfCircularChart>
                   <chart:PieSeries ItemsSource ="{Binding Data}" 
                                    XBindingPath="XValue" 
                                    YBindingPath="YValue"
                                    ShowDataLabels="True">
                   <chart:PieSeries.DataLabelSettings>
                        <chart:CircularDataLabelSettings LabelPosition="Outside" >
                            <chart:CircularDataLabelSettings.ConnectorLineSettings>
                               <chart:ConnectorLineStyle Stroke="Red" StrokeWidth="2" />
                            </chart:CircularDataLabelSettings.ConnectorLineSettings>
                        </chart:CircularDataLabelSettings>
                    </chart:PieSeries.DataLabelSettings>
                   </chart:PieSeries>
                </chart:SfCircularChart>

             # [C#](#tab/tabid-2)

                 SfCircularChart chart = new SfCircularChart();
                 ViewModel viewModel = new ViewModel();

                 PieSeries series = new PieSeries()
                 {
                    ItemsSource = viewModel.Data,
                    XBindingPath = "XValue",
                    YBindingPath = "YValue",
                    ShowDataLabels = true,
                 };

                 var connectorLineStyle = new ConnectorLineStyle
                 {
                   Stroke = new SolidColorBrush(Colors.Red),
                   StrokeWidth = 2
                 };
                 series.DataLabelSettings = new CircularDataLabelSettings()
                 {
                   LabelPosition="Outside"
                   ConnectorLineSettings = connectorLineStyle
                 };

                 chart.Series.Add(series);


             ***

member.example:
# [Xaml](#tab/tabid-5)

    <chart:SfCircularChart>
           <chart:PieSeries ItemsSource="{Binding Data}"                                                         
                            XBindingPath="Product"
                            YBindingPath="SalesRate"
                            ShowDataLabels="True">
               <chart:PieSeries.DataLabelSettings>
                   <chart:CircularDataLabelSettings LabelPlacement="Outer" ConnectorType="Curve"/>
               </chart:PieSeries.DataLabelSettings>
           </chart:PieSeries>
     </chart:SfCircularChart>

# [C#](#tab/tabid-6)

    SfCircularChart chart = new SfCircularChart();
    PieSeries series = new PieSeries();
    series.ItemsSource = new ViewModel().Data;
    series.XBindingPath = "Product";
    series.YBindingPath = "SalesRate";
    series.ShowDataLabels = true;
    series.DataLabelSettings = new CircularDataLabelSettings()
    {
       ConnectorType = ConnectorType.Curve,
       LabelPlacement = DataLabelPlacement.Outer
    };
    chart.Series.Add(series);


***

member.remarks:

By customizing these empty points, the positions of the data points are highlighted, thereby improving data visualization. 


EmptyPointSettings class provides properties to customize these empty points by modifying attributes such as , , and . 


To customize empty points, create an instance of , configure it as needed, and then add it to the series.


EmptyPointSettings is not supported for all area-related series, as well as for FastChart and ErrorBarSeries.
            # [MainPage.xaml](#tab/tabid-1)

            <chart:SfCartesianChart>

                    <chart:SfCartesianChart.BindingContext>
                        <local:ViewModel/>
                    </chart:SfCartesianChart.BindingContext>

                    <chart:SfCartesianChart.XAxes>
                        <chart:CategoryAxis/>
                    </chart:SfCartesianChart.XAxes>

                    <chart:SfCartesianChart.YAxes>
                        <chart:NumericalAxis/>
                    </chart:SfCartesianChart.YAxes>

                    <chart:SfCartesianChart.Series>
                       <chart:LineSeries ItemsSource = "{Binding Data}" XBindingPath="XValue" YBindingPath="YValue" EmptyPointMode="Zero"/>
                       <chart:LineSeries.EmptyPointSettings>
                               <chart:EmptyPointSettings Fill="Orange" Stroke="Red" StrokeWidth="3"/>
                           </chart:LineSeries.EmptyPointSettings>         
                   </chart:SfCartesianChart.Series>

            </chart:SfCartesianChart>


            # [MainPage.xaml.cs](#tab/tabid-2)

            SfCartesianChart chart = new SfCartesianChart();

            ViewModel viewModel = new ViewModel();
           	chart.BindingContext = viewModel;

            NumericalAxis xaxis = new NumericalAxis();
            chart.XAxes.Add(xaxis);	

            NumericalAxis yAxis = new NumericalAxis();
            chart.YAxes.Add(yAxis);

             LineSeries series = new LineSeries();
             series.ItemsSource = viewModel.Data;
             series.XBindingPath = "XValue";
             series.YBindingPath = "YValue";
             series.EmptyPointMode = EmptyPointMode.Zero;
             series.EmptyPointSettings = new EmptyPointSettings();
             series.EmptyPointSettings.Fill = Colors.Orange;
             series.EmptyPointSettings.Stroke = Colors.Red;
             series.EmptyPointSettings.StrokeWidth = 3; 
             chart.Series.Add(series);


            ***

